
import seaborn as sns
from sklearn.metrics import confusion_matrix
import matplotlib.pyplot as plt
import numpy as np
import pandas as pd

def save_zhu(C2):
    for i in range(51):
        with open('tdn_ucf.txt','a')as f:
            f.write(str(C2[i][i])+'\n')
def compare(cats):
    bigger=[]
    categories=[]
    with open('mamba_ucf.txt','r')as f:
        items_mamba=f.readlines()
    with open('tdn_ucf.txt','r')as f:
        items_tdn=f.readlines()
    for i in range(51):
        if items_tdn[i]<items_mamba[i]:
            with open('bigger_ucf.txt','a')as f:
                f.write(items_mamba[i]+' '+items_tdn[i]+' '+str(i)+' '+cats[i]+'\n')





def draw_max(cat1, cat2,cats):#cat1:真实值，cat2：预测值，cats：类别名称
 
    sns.set(font_scale=0.2)#font_scale：混淆矩阵中数字字体的大小倍数
    f,ax = plt.subplots(1,1)
    ranges=[s for s in range(51)]#categories分类类别个数
    C2 = confusion_matrix(cat1, cat2, labels=ranges,normalize='true')#normalize=true,pred,all
    save_zhu(C2)
    #打印 C2
    # print(C2)
    sns.heatmap(C2,annot=True,ax=ax,cmap='Reds',linecolor='white',square=True) #画热力图

    ax.set_xlabel('predict') #x 轴
    ax.set_ylabel('true') #y 轴
    labels=cats
    tick_marks = np.arange(len(labels))
    # print(tick_marks)
    plt.xticks(tick_marks, labels,rotation=90,fontsize=4)#调整X轴上标签的大小
    plt.yticks(tick_marks, labels,rotation=360,fontsize=4)#调整Y轴上标签的大小
    plt.savefig('max_hmbd51.png', bbox_inches='tight', dpi=400)
